  /**
     * Temporary method for dry run/testing purposes.
     * This method writes the users name , app name and 
     * corresponding AD group from which user is to be removed in a specified location.
     *
     * TODO: Remove this method after dry run testing in production.
     */

  public static void CSVWriter(List data) {

    // Specify the file path
    String path = "\\\\ANDC1WAPP0147.ds.sjhs.com\\IIQDataFiles\\";
    String csvFile = path+"delgateRemidiation_"+formatter.format(dd)+".csv";
    
    BufferedWriter writer = null;

    try  {

      
      writer = new BufferedWriter(new FileWriter(csvFile));
      for (List row : data) {
       
        writer.write(String.join(";", row));
        writer.newLine();
      }


     
      writer.flush(); // Flushes the buffer

      log.error("CSV file created successfully.");
    } catch (IOException e) {
      log.error("Exception :"+e);
      throw new GeneralException("Exception :"+e);
    }

    finally {
      if (writer != null) {
        try {
          // Close the writer to release resources
          writer.close();
        } catch (IOException e) {
          log.error("Exception :"+e);
          throw new GeneralException("Exception :"+e);
        }
      }
    }
  }
  
  /**
   * Method to remove an account from an AD group plan.
   * 
   * @param identity The identity of the user.
   * @param link     The link to the account.
   * @param adGroup  The AD group name.
   * @param app      The application name.
   *
   * @return logAugdit flag a boolean value , true if provisioning is scussesful and false if provisioning fails.
   * @throws GeneralException if an error occurs during the Provisioning Process.

   */  

  public static boolean removeAccountFromADGroupPlan(Identity identity, Link link, String adGroup, String app){


    boolean logAudit = false;
    info(logName, "Starting method removeAccountFromADGroupPlan");

    // Create a provisioning plan to remove the group
    sailpoint.object.ProvisioningPlan plan = new sailpoint.object.ProvisioningPlan();

    sailpoint.object.ProvisioningPlan.AccountRequest accountRequest = new sailpoint.object.ProvisioningPlan.AccountRequest();
    accountRequest.setApplication(app);
    accountRequest.setNativeIdentity(link.getNativeIdentity());
    accountRequest.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
  
    accountRequest.add(new sailpoint.object.ProvisioningPlan.AttributeRequest(ATTR_AD_GROUP_ATTR_NAME, ProvisioningPlan.Operation.Remove, adGroup));

    plan.add(accountRequest);
    plan.setIdentity(identity);
    plan.setNativeIdentity(identity.getName());

    debug(logName, "Plan generated for delegate remediation :"+plan.toXml());

/**
     * Temporarily commented Try-Catch block for dry run/testing purposes.
     * This will refrain from triggering any provisioning.
     *
     * TODO: Uncomment the Try-Catch block after dry run testing in production.
     */

/*
// Execute the provisioning plan
    try {
      Provisioner provisioner = new Provisioner(context);
      ProvisioningProject project = provisioner.compile(plan);
      provisioner.execute(project);

      ProvisioningProject projec = provisioner.getProject();

      List plans = projec.getPlans();

      if(plans != null && !plans.isEmpty()){


        for(sailpoint.object.ProvisioningPlan pl : plans){

          List accReqList = pl.getAccountRequests(app);

          if (accReqList != null && accReqList.size() > 0) {
            for (AccountRequest accReq : accReqList) {
              if (accReq.getResult() != null && ProvisioningResult.STATUS_COMMITTED.equals(accReq.getResult().getStatus())) {

                logAudit = true;

              }
            }
          }
        }


      }

    }catch (GeneralException e) {
    
      error(logName, "Error removing group from identity: " + identity.getName() + ", Error: " + e.getMessage());
    }
*/
    info(logName, "End method removeAccountFromADGroupPlan");

    return logAudit;
  }


  /**
   * Logs an audit event for the delegate remediation process.
   * 
   * @param identityName The name of the identity.
   * @param adGroup      The AD group name.
   * @param appName      The application name.
   * @param link         The link to the account.
   */
  public static void logAuditEvent(String identityName, String adGroup, String appName, Link link){

    info(logName, "Starting method logAuditEvent");
    String target = identityName;

    String action = "delegateRemediation";


    if (Auditor.isEnabled(action)){
      AuditEvent eventIIQ = new AuditEvent();

      eventIIQ.setTarget(target);
      eventIIQ.setAction(action);
      eventIIQ.setString1("Remove Operation");
      eventIIQ.setApplication(appName);
      eventIIQ.setAttributeName(ATTR_AD_GROUP_ATTR_NAME);
      eventIIQ.setAttributeValue(adGroup);
      eventIIQ.setAccountName(link.getNativeIdentity());

      Auditor.log(eventIIQ);

      context.saveObject(eventIIQ);

    }

    info(logName, "End method logAuditEvent");
  }





  /**
   * Performs delegate remediation by processing a list of group members.
   * 
   * @param adGroupMem List of members in the AD group.
   * @param appN       The application name.
   * @param adGroup    The AD group name.
   */

  public static void delegateRemediation(List adGroupMem, String appN, String adGroup){

    info(logName, "Starting method delegateRemediation");

    for(String idName : adGroupMem){
      
      debug(logName, "processing for Identity :"+idName);

      Identity identity = context.getObjectByName(Identity.class, idName);
      Identity manager = identity.getManager();

      if(manager == null || manager.isInactive()){
      debug(logName, "Manager is inactive or null for :"+idName);

        List link = new ArrayList();

        link = queryUtil.getIdentityAppLinks(identity.getName(), appN);

        if(link != null && !link.isEmpty()){

          for(Link l : link){

            if(null != l.getAttributes().get("memberOf")){

              if(l.getAttributes().get("memberOf").contains(adGroup)){

                boolean auditFlag = removeAccountFromADGroupPlan(identity, l, adGroup, appN);

                usersRemoved.add("USER ->"+identity.getName()+" REMOVED FROM-> "+adGroup);

               
//*********************Temporary code for dry run/testing purposes**************************//
                List row = new ArrayList();
                row.add(identity.getName());
                row.add(adGroup);
                row.add(appN);
                data.add(row);
//*********************Temporary code for dry run/testing purposes**************************//

                if(auditFlag){

                  logAuditEvent(identity.getName(), adGroup, appN, l);

                }



              }else{
      
                debug(logName, "On Identity Object entitlement or memberOf :"+adGroup+" is not present for "+idName);

              }
            }else{

      
              debug(logName, "memberof attribute is Empty for :"+idName);
            }


          }

        }
        else{

      
          debug(logName, appN+" applink not present for user :"+idName);
        }


      }
      else{

      
        debug(logName, "Manager is active , Ignoring Identity "+idName+" from delegate remediation");
      }

      context.decache(identity);

    }

    info(logName, "End method delegateRemediation");

}

  /**
   * Fetches members of an AD group.
   * 
   * @param group The name of the AD group.
   * @return List of members in the AD group.
   */

  public static List fetchAdGroupsMembers(String group){

    info(logName, "Starting method fetchAdGroupsMembers");
    
    debug(logName, "processing for AD Group :"+group);

    Iterator it = null;
    props.add("name");
    List groupMembers = new ArrayList();

    QueryOptions qo = new QueryOptions();
    Filter filter = Filter.ignoreCase(Filter.and(Filter.eq("identityEntitlements.name",ATTR_AD_GROUP_ATTR_NAME), Filter.eq("identityEntitlements.value",group)));

    qo.addFilter(filter);

    try {
      it=context.search(Identity.class,qo,props);

      while(it.hasNext())
      {
        String name = (String)((Object[])it.next())[0];
        groupMembers.add(name);

      }
    }catch (Exception e) {

      error(logName, "Error processing fetchAdGroupsMembers for group " + group, e);
    }
    Util.flushIterator(it);
    return groupMembers;

    info(logName, "End method fetchAdGroupsMembers");

  }




  try{

    info(logName, "Starting HouseKeeping Task for Delegate Remediation");

    Custom cust = context.getObjectByName(Custom.class, CUSTOM_OBJ_NAME);


    if (cust != null) {

      if(null != cust.getAttributes().get("appEntMapping")){

        for(String appN : cust.getAttributes().get("appEntMapping").keySet()){

          List adGroupList = new ArrayList();

          adGroupList = cust.getAttributes().get("appEntMapping").get(appN);
          if(adGroupList != null && !adGroupList.isEmpty()){

            debug(logName, "processing for Application :"+appN);

            for(String adGroup : adGroupList){

              List adGroupMem = new ArrayList();

              adGroupMem = fetchAdGroupsMembers(adGroup);

              if(adGroupMem != null && !adGroupMem.isEmpty()){


                delegateRemediation(adGroupMem, appN, adGroup);

              }
              else{


                warn(logName, "Either group not present or members not present for :"+adGroup);
              }


            }
          }
          else{

            error(logName, "No AD groups present for entry :"+appN);

          }
        }

//*********************Temporary Method call for dry run/testing purposes**************************//
CSVWriter(data);
//*********************Temporary Method call for dry run/testing purposes**************************//

      }else{
        throw new RuntimeException("ERROR: AD Groups not Present in Custom Object"); 

      }
    }
    else{
      throw new RuntimeException("ERROR: Custom Object is Empty"); 
    }
  }catch (Exception e) {
    throw new RuntimeException("Error processing Delegate Remediation Rule", e);

  }


  context.commitTransaction();
  context.decache();

  info(logName, "End HouseKeeping Task for Delegate Remediation");


  if (taskResult != void) {


    if(usersRemoved != null && !usersRemoved.isEmpty()){

      taskResult.addAttribute("Delegate Remediation", Util.join(usersRemoved, "\n"));



    }
    else{

      taskResult.addMessage("No Delegation Remediation Occured.");

    }  

  }
